var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어젠 이상한 손님이 오는 바람에 눈치만 보다가 엉겁결에 퇴근까지 해버렸네요.","JPN":"昨日は変なお客様が来たせいで顔色を伺うばかりで、\\nあたふたするうちに仕事が終わってしまいました。","ENG":"Last night, I got distracted by some strange customer. I totally forgot about what I was going to do until I got off work.","TWN":"都是因為昨天那個奇怪的客人，害我提早下班。"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만, 오늘에야말로 악마와 담판을 짓겠어요!","JPN":"ですが、今日こそ悪魔と決着をつけます！","ENG":"But not today. I'm going to finish that devil, no matter what!","TWN":"今天一定要跟魔鬼做個了結！"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…응?","JPN":"……あれ？","ENG":"Hmm?","TWN":"…嗯？"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"뒤처리는 제대로 했겠지?","JPN":"後始末は問題ないな？","ENG":"You took care of everything, right?","TWN":"都有處理乾淨吧？"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"그래, 그 여자 완전히 곯아떨어져서 아무것도 모르던데?","JPN":"もちろん。あの女、完全に酔いつぶれて何も気づいてなかったぞ。","ENG":"Of course. She was so drunk, she had no idea.","TWN":"那當然，那女的完全醉得不省人事！"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_B","text":{"KOREA":"방에 술 냄새가 어찌나 심하게 진동을 하던지. 코가 마비되는 줄 알았다니까.","JPN":"店内の酒の臭いが本当にすごいな。鼻が麻痺するかと思ったぞ。","ENG":"The whole place smelled of alcohol. I couldn't breathe!","TWN":"房裡的酒味濃到我以為我的鼻子會壞掉。"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_NPC_POISONRAT_A","text":{"KOREA":"좋아. 돌아가는 대로 보스한테 보고하자고.","JPN":"よし、戻り次第ボスに報告しよう。","ENG":"Alright, let's report back to the Boss.","TWN":"很好，趕快回去報告老大吧！"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"휴, 하마터면 마주칠 뻔했어요.","JPN":"ふう、危うく出くわすところでした。","ENG":"Whew! Thank God, they didn't see me.","TWN":"呼，差點就撞到他們。"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저 복장은 분명… 제가 얼마 전에 마주쳤던 죄인들이네요.","JPN":"あの服装は確か……私がこの前出会った罪人たちですね。","ENG":"Their clothes... They're the sinners I encountered a while ago.","TWN":"看他們那身造型…就是我之前遇到的那些壞蛋吧！"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그런데 어째서 저희 가게에서 나온 걸까요?","JPN":"なぜうちの店に来たのでしょう？","ENG":"And why did they come out of my shop?","TWN":"不過他們為什麼會從我們店裡走出來？"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"설마… 그레모리 씨에게 나쁜 짓을 저지르기라도 한 건?!","JPN":"まさか……グレモリーさんに何か悪いことを！？","ENG":"Oh, no! What if they hurt Gremory?","TWN":"難道…他們該不會對葛茉莉不利吧？"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨!","JPN":"グレモリーさん！","ENG":"Gremory!","TWN":"葛茉莉！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으음…","JPN":"ううん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"테이블에 처참하게 널브러져 계신 그레모리 씨…","JPN":"テーブルの上で無防備な状態で泥酔しているグレモリーさん……","ENG":"Gremory is sprawled half across the table...","TWN":"狼狽地攤在桌下的葛茉莉…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다행히 평소 모습 그대로예요.","JPN":"よかった、いつもと同じです。","ENG":"As usual. Thank God!","TWN":"完全跟平常一樣呢，好險！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으으… 머리야… 햇빛 싫어…","JPN":"うう……頭痛い……日光嫌い……","ENG":"Aww... My head... I hate sunlight...","TWN":"噢嗚…我的頭…陽光好刺眼…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"또 밤새도록 드신 거예요? 건강에 안 좋다고 말씀드렸잖아요.","JPN":"また夜通しで飲んだんですか？　体に悪いって何度も言ったのに。","ENG":"Did you drink all night again? I told you it's bad for your health.","TWN":"你又喝一整晚嗎？不是跟你說這樣有害健康嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"커튼… 다시 쳐 줘어…….","JPN":"カーテン……閉めてちょうだい……","ENG":"The curtains... Close them please...","TWN":"窗簾…拉起來……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"안 돼요. 이제 청소 시작할 거니까 일어나세요.","JPN":"だめですよ。これから掃除をするので起きてください。","ENG":"No. I'm going to start cleaning now. Get up.","TWN":"不可以，我現在要打掃店裡，請你起來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그런데… 모모는 어디에 있는 거죠?","JPN":"ところで……モモはどこにいるんですか？","ENG":"By the way... where's Momo?","TWN":"不過…怎麼沒看到莫莫？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…모모?","JPN":"モモ？","ENG":"Momo?","TWN":"…莫莫？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"납치당했다.","JPN":"攫われたの。","ENG":"Kidnapped.","TWN":"他被綁架了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…네?","JPN":"……えっ？","ENG":"What?","TWN":"…蛤？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에에에?!","JPN":"ええええっ！？","ENG":"Whaaaat?","TWN":"你說什麼？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무엄하도다, 인간들! 이 몸을 여기서 내보내지 못하겠느냐!","JPN":"無礼だぞ、人間ども！　吾輩をここから出さないと許さんぞ！","ENG":"How dare you, you foolish humans? Let me out of here!","TWN":"大膽刁民！還不快放本王走！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L41_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"꼬맹이. 정신 사나우니까 소리 좀 그만 질러.","JPN":"ガキ。気が散るからいい加減黙ってろ。","ENG":"Hey, kiddo. You're going to make my ears bleed. Stop screaming.","TWN":"小鬼，安靜點，你好吵！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"에극!","JPN":"ぐっ……！","ENG":"Ow!","TWN":"哎唷！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_DAMAGE_DOWN"},{"id":"L43_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으히잉……. 아파…….","JPN":"ひぃーん……痛い……","ENG":"Hnnnggg... That hurt...","TWN":"嗚嗚嗚……好痛喔……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_B","text":{"KOREA":"이봐, 아무리 시끄럽다고 해도 애 머리를 때리면 어떡해?","JPN":"おい、うるさいからって子どもをぶっちゃダメだろ。","ENG":"Hey, so she screamed a little bit. Was it really necessary to hit her on the head?","TWN":"喂，我知道她很吵，但你怎麼可以打小朋友的頭呢！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"내, 내가 안 그랬어! 갑자기 천장에 있던 파이프가 떨어져서 맞은 거라고!","JPN":"お、俺はやってねえぞ！　急に天井からパイプが落ちて当たっただけだ！","ENG":"I-I didn't do it! A pipe dropped from the ceiling!","TWN":"我…我沒有！是天花板的排風管突然掉下來砸到她！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_B","text":{"KOREA":"조심해. 데려오는 동안에도 발버둥치다 가로등에 머릴 들이받았잖아.","JPN":"気をつけろ。ここに来る時も暴れまくって電柱にぶつかったんだろ。","ENG":"We'd better be careful. Earlier, she hit her head on a light pole trying to get away from us.","TWN":"你小心點！我們把她綁來的路上，她不就因為掙扎結果撞到路燈嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_B","text":{"KOREA":"인질이 너무 다치면 협상이 불리해질 수도 있어.","JPN":"人質が怪我しすぎると交渉が不利になるかもしれない。","ENG":"A banged-up hostage could damage our negotiation.","TWN":"人質傷得太重的話，很可能會不利於談判！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"쳇, 평의회 작자들이 우리 영역을 꿰찬 뒤로 약장사도 망하고 들어오는 의뢰도 영 시원찮으니… 이젠 급 떨어지게 애를 데리고 납치극까지 벌이는구만.","JPN":"ちっ、評議会のやつらに縄張りを乗っ取られてから、\\nブツも売れないし依頼も減りまくって……\\n今じゃガキを攫って脅迫する羽目になるとはな、俺らも堕ちたもんだ。","ENG":"Gah, ever since the Dark Council started encroaching upon our territory, we've been losing drug deals and contract work altogether. Now, we're holding a child hostage for ransom. Unbelievable.","TWN":"嘖，評議會的傢伙搶走我們的地盤後，毒品的生意也做不好，收到的也都是些亂七八糟的委託…現在連綁架小孩的勾當也要幹！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_B","text":{"KOREA":"걱정 마. 이번 건만 잘 풀리면 나머지 문제도 다 해결될 거라고 보스가 장담했으니까.","JPN":"心配すんな。今回の件さえうまくいけば、他の問題も解決できるってボスが言ってただろ。","ENG":"Don't worry. The Boss said if this goes well, everything else will work itself out.","TWN":"安啦！老大不是跟我們掛保證，說只要這件事處理好，其他問題也會迎刃而解嗎！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"배고파.","JPN":"お腹空いた。","ENG":"I'm hungry.","TWN":"我肚子餓。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_STARVE"},{"id":"L4_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_B","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hm?","TWN":"什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"배가 고프구나. 먹을 걸 다오.","JPN":"お腹が減った。食べ物をくれ。","ENG":"I'm hungry. Give me food.","TWN":"我說我肚子餓要吃東西！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_B","text":{"KOREA":"참아. 우리 먹을 것도 없어.","JPN":"我慢しろ。俺らだって食うもんなんかねえんだ。","ENG":"Deal with it. We don't even have food for ourselves.","TWN":"忍耐點，我們沒東西吃！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"달콤한 거 먹고 싶도다! 달콤한 거!","JPN":"吾輩は甘いものが食べたいのだ！　甘いもの！","ENG":"I want something sweet. Something sweet!","TWN":"我想吃甜甜的東西！甜甜的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L9_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"아, 그러고 보니 알사탕이 하나 남아있긴 한데. 먹을래?","JPN":"あ、そういえば飴が一個あるんだが、食うか？","ENG":"Ah, now that I think of it, I do have a jawbreaker. Do you want it?","TWN":"喔！我想起來好像還有一顆糖，你要吃嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오오, 사탕을 가지고 있다니. 나쁜 녀석치곤 기특한 인간이로다.","JPN":"おお、キャンディを持っているとは。悪い人間の割には偉いやつだ。","ENG":"Ooo, candy! You're not too bad for a villain.","TWN":"哇，壞人竟人身上會有糖果，真是特別的壞人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그걸 주면 네 녀석은 특별히 그레모리에겐 덜 혼내라고 말해 주마.","JPN":"それをくれたら、お前は特別扱いで\\nグレモリーにはあまり怒らないように言っておいてやろう。","ENG":"If you give it to me, I'll tell Gremory to go easy on you.","TWN":"你把糖果給我的話，我就叫葛茉莉少罵你一點。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"여기. 마음껏 먹으라고.","JPN":"ほれ、好きに食べろ。","ENG":"Here. Enjoy.","TWN":"想吃就拿去吧！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"…아앗! 안 돼!","JPN":"……ああっ！　危ない！","ENG":"Ah! No!","TWN":"…哎呀！不可以！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"어이쿠, 실수로 떨어트렸네.","JPN":"おっと、うっかり落としてしまったな。","ENG":"Oops, I dropped it by accident.","TWN":"哎呀～不小心掉到地上咧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"어쩌지? 부스러기라도 줄까?","JPN":"どうしようか？　残りカスでもやろうか？","ENG":"I'm sorry. I still have some crumbs on my hand. Do you want 'em?","TWN":"怎麼辦？你還要吃嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으으…!","JPN":"むう……！","ENG":"Grr!","TWN":"嗚嗚…！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"일부러 버리는 거 못 본 줄 아느냐! 못된 녀석이로다!","JPN":"わざと捨てたのがバレバレだったぞ！　悪い奴め！","ENG":"I saw you drop it on purpose! You're bad!","TWN":"你以為我沒看到你是故意的嗎！你這個大壞蛋！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_NULL","text":{"KOREA":"소란 피우지 마. 건물이 낡아서 방음도 잘 안 된다고.","JPN":"そんなに騒ぐな。ボロい建物だから音が外に漏れるだろ。","ENG":"Keep her quiet. This building is so old. People outside can hear her.","TWN":"不要節外生枝，這個地方很老舊，隔音設備也不太好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"엇, 보스! 오셨습니까!","JPN":"あっ、ボス！　お疲れ様です！","ENG":"Ah, Boss!","TWN":"老大！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아앗! 네놈! 어제 가게에 왔던 수상한 손님!","JPN":"お前は！　昨日お店に来た怪しい客！","ENG":"Aah! You! You were the suspicious customer yesterday!","TWN":"喔！！是你！昨天來店裡的奇怪客人！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"전부 네 녀석이 저지른 짓이로구나!","JPN":"全部お前の仕業だな！","ENG":"You're behind all this!","TWN":"這全都是你這傢伙幹得好事嗎！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_NULL","text":{"KOREA":"시끄러워!","JPN":"やかましい！","ENG":"Shut up!","TWN":"吵什麼吵！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CLATTER"},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"힉…!","JPN":"ひッ……！","ENG":"Heek!","TWN":"嗚…！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_NULL","text":{"KOREA":"젠틀하게 대해 주려 했더니 제 집 안방처럼 떠들어대는군.","JPN":"ジェントルに接してやろうとしたのに、好き勝手に騒ぎ立てやがって。","ENG":"I was going to be gentle with you, but you're way too loud for my liking.","TWN":"不要以為我很紳士，給你點顏色，你就給我開起染房來！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOSS_NPC_POISONRAT_NULL","text":{"KOREA":"조용히 못 시키겠으면 입이라도 막아.","JPN":"静かにさせられないなら、口を塞いでおけ。","ENG":"If she doesn't shut up, gag her.","TWN":"她不能乖乖閉嘴的話，就把她的嘴給我堵起來！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEMBER_NPC_POISONRAT_A","text":{"KOREA":"넵! 그렇게 하죠!","JPN":"はっ！　そうします！","ENG":"Yes, sir!","TWN":"是！收到！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"시… 싫다! 저리 물러나지 못하겠느냐!","JPN":"い、いやだ！　あっちいけ！","ENG":"N-no! Stay away!","TWN":"唔…我不要！給我走開！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"……흐에엑!","JPN":"……ほええっ！","ENG":"Heek!","TWN":"……唔唔！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MEMBER_NPC_POISONRAT_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……포이즌랫이요?","JPN":"……ポイズンラットですか？","ENG":"Poison Rats?","TWN":"……毒鼠幫？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"화학물질을 칵테일이라고 부르는 도시의 흔한 괴짜 범죄조직 중 하나지.","JPN":"化学物質をカクテルと呼ぶ都市によくある変わり者の犯罪組織の一つよ。","ENG":"They're one of many crazy criminal organizations in the city that likes to call chemical compounds \\"cocktails.\\"","TWN":"就是都市裡常見的犯罪組織之一。他們將化學物質稱為雞尾酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"독극물이든 폭발물이든 가리지 않고 만들어 팔던 녀석들이야.","JPN":"毒物であれ爆発物であれ、関係なく作って売っていた連中なの。","ENG":"They make poisons, explosives, and anything else they can think of that they can make money with.","TWN":"賣的東西包括毒品和炸藥。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"예전엔 약 장사가 본업이었는데, 성냥이라는 신종 때문에 불경기가 온 뒤로 이것저것 손을 댔나 봐.","JPN":"昔はドラッグの商売が本業だったけど、マッチという新種ドラッグのせいで\\n不景気になってから、いろんなことに手を出したみたい。","ENG":"Before, they mainly dealt drugs, but they were pushed out of that business by this new thing named the Matches. Since then, they've been dealing everything they can get their hands on.","TWN":"他們原本是專門賣毒品的，不過生意被一個叫火柴的新興組織搶走後，就開始亂槍打鳥，什麼都做。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 뒤로도 여전히 잘 안 풀리는 모양이지만.","JPN":"その後も相変わらずうまくいってないようだけどね。","ENG":"Still, they're not doing as well as they used to.","TWN":"只是似乎依舊沒有起色。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼…… 어제 왔던 그 손님이 포이즌랫의 보스라는 거죠?","JPN":"では、昨日来たあのお客様がポイズンラットのボスということですね？","ENG":"So, the customer yesterday is their boss.","TWN":"所以……昨天來店裡的那位客人，就是毒鼠幫的老大吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨는 이렇게 될 줄 알고서도 술이나 마시고 계셨던 거고요!","JPN":"グレモリーさんはこうなるとわかっていて、お酒を飲んでいたんですか！？","ENG":"And you've been drinking even though you knew this was going to happen. How could you?","TWN":"葛茉莉，你明知道會發生這種事，還有心情喝通宵嗎！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나도 몰랐어.","JPN":"アタシだってわからなかったわ。","ENG":"I didn't know.","TWN":"我不知道。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"두고 보라던 놈이 설마 다녀간 날 밤에 바로 일을 벌일 줄이야.","JPN":"次に来る時まで考えろって言っていた奴が、\\nまさか来た日の夜にすぐ動き出すなんてね。","ENG":"He told me to think about his offer. Who knew he'd do this the next day?","TWN":"我以為他只是嘴巴上說走著瞧，誰知道他會當晚就動手？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 걱정 마. 임금님에겐 별일 없을 거야.","JPN":"でも心配しないで。王様なら平気だと思うわ。","ENG":"But don't worry. She will be fine.","TWN":"不過你放心啦，國王沒事的。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…네?","JPN":"……はい？","ENG":"What?","TWN":"…沒事？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"별일 없을 거라니… 그게 무슨 소리죠?","JPN":"平気って……それはどういう意味ですか？","ENG":"How do you know she'll be fine?","TWN":"你怎麼知道她沒事…這是什麼意思？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"말 그대로야. 니콜 양이 걱정하는 그런 일은 안 일어나.","JPN":"言葉どおりよ。ニコルちゃんが心配しているようなことは起こらないの。","ENG":"I just do. Nothing that you're worried about will happen to her.","TWN":"就是我說的那個意思，你擔心的事不會發生的～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"지금까지 봐왔으니 알잖아? 우리 임금님이 얼마나 강한 아이인지.","JPN":"今まで見てきたからわかるでしょ？　うちの王様がどれだけ強い子なのか。","ENG":"You've been with her. You know how strong she is.","TWN":"你這幾天跟她相處還不知道嗎？她是個多麼堅強的孩子！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우리끼리 한잔하고 있으면, 어련히 알아서 돌아올 거야.","JPN":"ここで一杯飲んでいれば、そのうち帰ってくるわ。","ENG":"Let's just have a drink. She'll come back on her own.","TWN":"說不定在我們喝一杯的時候，她就自己回來了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"강한 아이라고요?","JPN":"強い子ですって？","ENG":"She's strong?","TWN":"堅強的孩子？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜. 배고프다. 먹을 거 없느냐?","JPN":"ニコル、お腹がすいた。食べ物はないか？","ENG":"Nicole, I'm famished. Where's the food?","TWN":"妮可，我肚子餓，有東西吃嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_STARVE"},{"id":"L16_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 니콜이 만든 스무디가 제일 맛있도다!","JPN":"吾輩はニコルが作ったスムージーが一番好きなのだ！","ENG":"I love your smoothies more than anything in the world!","TWN":"本王最喜歡妮可做的冰沙！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"걱정도 참 많은 하수인이로구나.","JPN":"心配性の下僕だな。","ENG":"My subject, you're such a worrywart.","TWN":"真是個很會操心的手下呢！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜이 되찾아준 지갑이다. 이제 안 잃어버리니 걱정 말 거라!","JPN":"ニコルが取り戻してくれたお財布だ。\\n二度と無くさないから心配するな。","ENG":"You got me my purse back. Don't worry. I'll never lose it again!","TWN":"這是妮可幫我討回來的錢包，從現在起我不會再弄丟的，你放心吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"잘 때도 꼭 안고 자도록 하겠노라.","JPN":"寝るときも必ずぎゅっと握って寝るとしよう。","ENG":"I'll go to bed with it.","TWN":"連我睡覺的時候也會緊緊抱著它！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모는…….","JPN":"モモは……","ENG":"Momo...","TWN":"莫莫她……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응?","JPN":"んっ？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모는 그레모리 씨가 생각하는 그런 강한 아이가 아니에요.","JPN":"モモはグレモリーさんが思うような強い子ではありません。","ENG":"Momo is not as strong as you think she is, Gremory.","TWN":"莫莫沒有你想得那麼堅強。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"단 것만 찾을 줄 아는 편식쟁이에 음식만 축내고…","JPN":"甘いものに目がない偏食家で、仕事もせず食べてばかりで……","ENG":"She's a glutton who wants nothing but sweets.","TWN":"她很挑食，只吃甜食，都不吃正餐…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님들 앞에서 직원답게 행동하긴커녕 매일 같이 폐만 끼치고…","JPN":"お客様の前でスタッフらしく振る舞うどころか、\\n毎日のように問題ばかり起こして……","ENG":"She bothers our customers instead of helping me.","TWN":"在客人面前也不像個員工，整天只知道惹麻煩…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"밖에 놀러 나가는 날이면 항상 칠칠찮게 다쳐 가지곤 울면서 돌아와요.","JPN":"おっちょこちょいすぎて、\\n外に遊びに行く日は怪我をして泣きながら帰ってくるんです。","ENG":"And every time she goes outside alone, she comes back crying because she hurt herself.","TWN":"出去玩的話，不是傷到這裡，就是傷到那裡，然後哭哭啼啼地跑回來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"누가 지켜줄 필요가 없는… 그런 강한 아이가 아니라고요.","JPN":"誰かが守る必要がない……そんな強い子ではありません。","ENG":"She's not so strong that she can fend for herself.","TWN":"她才不是堅強到…不需要大人保護的孩子！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래서, 우리 니콜 양은 어떻게 하고 싶은데?","JPN":"それで、ニコルちゃんはどうしたいの？","ENG":"So? What are you going to do about that, Nicole?","TWN":"那妮可你打算怎麼做？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 그야 당연히!","JPN":"はい？　それはもちろん！","ENG":"Huh? Of course, I—","TWN":"什麼？當然是！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"당연히…….","JPN":"もちろん……","ENG":"Of course, I...","TWN":"當然是……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"성자의 이름으로 세상의 모든 악마를 남김없이 처단하는 것.","JPN":"聖者の名のもとに、この世のすべての悪魔を残さず祓うこと。","ENG":"To punish all the devils in the world in the name of the Son.","TWN":"以聖者之名，驅除世界上一切的魔鬼，"},"stage":{"bg":"CHURCH","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRIEST_NPC_VATICAN_NULL","text":{"KOREA":"그것이 구마회의 소명.","JPN":"それが祓魔会の使命。","ENG":"That's the purpose of the Exorcism Council.","TWN":"這就是驅魔會的使命。"},"stage":{"bg":"CHURCH","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"네 행동에서 중요한 건 평가하는 사람이 아닌 자기 의지니까.","JPN":"あなたの行動で大事なのは、評価する人ではなく自身の意思なんだから。","ENG":"What matters is what you think of it.","TWN":"因為最重要的不是其他人怎麼想，而是你怎麼想。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"네가 옳다고 생각한다면, 그걸로 충분한 거야.","JPN":"あなたが心から正しいと思ったなら、それで十分よ。","ENG":"If you think it's the right thing to do, then it is.","TWN":"若你覺得這是對的，這個理由就已經很充分。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"어둠 속에서 길을 밝혀주는 등불은 오로지 자매님의 신앙뿐.","JPN":"暗闇の中で道を照らす灯りは、ただシスターの信仰のみ。","ENG":"Only your faith can guide you along the path shrouded in darkness.","TWN":"能夠在黑暗中為你指引明路的，唯有你的信仰。"},"stage":{"bg":"CHURCH","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"\\n그럼에도 이 길을 걸으시렵니까?","JPN":"\\nそれでもこの道を歩むと誓いますか？","ENG":"\\nAre you sure you want to walk this path?","TWN":"\\n即便如此，你願意選擇這條路嗎？"},"stage":{"bg":"CHURCH","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"적성에 맞는 일이라는 것도 마찬가지 아닐까?","JPN":"それなら、適性がある仕事も同じじゃないかしら。","ENG":"But that also applies to what you do, doesn't it?","TWN":"應用在工作上不也是一樣的道理嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"\\n짧은 시간 동안 하나의 단면만을 보고서 그 길이 전부 잘못됐다고 확신할 순 없는 거야.","JPN":"\\n短時間で一つの側面だけを見て、\\nその道が全部間違っていると確信することはできないの。","ENG":"\\nYou can't tell if it's right or wrong after experiencing it only for a short period.","TWN":"\\n這麼短的時間內，你對這份工作只有片面的認識，怎麼能夠確定這條路是錯的呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 애가 위험에 빠진 걸 알면서도 모른 척 남겨둘 수 없어요.","JPN":"あの子が危険に晒されたことを知りながら、\\n知らないふりをするわけにはいきません。","ENG":"I can't ignore her when I know she's in danger.","TWN":"我不能眼睜睜看著她遇到危險，卻視而不見。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제게 주어진 의무가 무엇이든… 그거 하나만은 분명한 사실이에요.","JPN":"私に与えられた義務が何であれ……それだけは明らかな事実です。","ENG":"Regardless of my duty, that's a fact.","TWN":"無論我的使命是什麼…但唯有這件事是我必須要去做的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러니까, 제가 모모를 구하겠어요.","JPN":"だから、私がモモを救い出します。","ENG":"So, I'm going to save Momo.","TWN":"所以，我要去救莫莫！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"멋지네. 잘 해 봐.","JPN":"かっこいいわね。頑張って。","ENG":"Great. Good luck.","TWN":"帥喔，加油。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다녀오겠습니다.","JPN":"行ってきます！","ENG":"I'll be back.","TWN":"等我好消息！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하아, 한창 귀여울 때라니까.","JPN":"もう、本当にかわいいんだから。","ENG":"Ooh, how cute she is!","TWN":"哈哈，正是青春可愛的時候呢～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아, 그러고 보니…","JPN":"あ、そういえば……","ENG":"Ah, wait a minute...","TWN":"不過…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"지난번처럼 길이나 잃진 않으려나?","JPN":"また迷子になったりはしないかしら？","ENG":"What if she gets lost like last time?","TWN":"她該不會跟上次一樣迷路吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};